/**
 * Core types for the harness orchestrator
 */

export interface Feature {
  id: string;
  category: string;
  description: string;
  steps: string[];
  passes: boolean;
  blockedBy: string | string[] | null;
  notes?: string;
}

export interface HarnessConfig {
  project: string;
  version: string;
  description: string;
  lastUpdated: string;
  goals: string[];
  features: Feature[];
  architecture?: {
    overview: string;
    components: Record<string, string>;
    dataFlow: string[];
  };
  considerations?: Record<string, string>;
}

export type TaskStatus = 'pending' | 'ready' | 'running' | 'completed' | 'failed';

export interface Task {
  feature: Feature;
  status: TaskStatus;
  startedAt?: Date;
  completedAt?: Date;
  error?: string;
  agentId?: string;
}

export interface AgentInfo {
  id: string;
  taskId: string;
  pid?: number;
  status: 'idle' | 'busy' | 'error';
  startedAt: Date;
}

export type ModelType = 'haiku' | 'sonnet' | 'opus';

export interface OrchestratorOptions {
  maxAgents: number;
  defaultModel: ModelType;
  dryRun: boolean;
  timeout: number;
  featuresPath: string;
}

export interface SchedulerResult {
  completed: string[];
  failed: string[];
  remaining: string[];
  duration: number;
}
